const readyRows = $input.all().map((item) => item.json);
const rows = readyRows.map((row) => ({
  revenue_event_key: row.revenue_event_key,
  anchor_line_item_id: row.anchor_line_item_id ?? null,
  anchor_invoice_id: row.anchor_invoice_id,
  anchor_relationship_id: row.anchor_relationship_id ?? null,
  macro_service_type: row.macro_service_type,
  source_amount: Number(row.source_amount ?? 0),
  recognized_amount: Number(row.recognized_amount_to_apply ?? 0),
  recognition_status: row.next_recognition_status ?? 'recognized_by_completion_trigger',
  recognition_rule: row.recognition_rule,
  candidate_period_month: row.candidate_period_month ?? null,
  recognition_date: row.recognition_date_to_apply,
  recognition_period_month: row.recognition_period_month_to_apply,
  trigger_source: row.source_system,
  trigger_reference: row.trigger_reference_to_apply,
  notes: `Recognized by ${row.trigger_type} trigger ${row.recognition_trigger_key}.`,
  loaded_at: new Date().toISOString(),
}));

const recognizedAmount = rows.reduce((sum, row) => sum + Number(row.recognized_amount ?? 0), 0);
const byMacro = rows.reduce((acc, row) => {
  acc[row.macro_service_type] = (acc[row.macro_service_type] ?? 0) + 1;
  return acc;
}, {});

return [
  {
    json: {
      rows,
      summary: {
        readyRevenueEventCount: rows.length,
        recognizedAmount: Math.round(recognizedAmount * 100) / 100,
        byMacro,
      },
    },
  },
];

const rows = $input.all().map((item) => item.json);
const recognizedAmount = rows.reduce((sum, row) => sum + Number(row.recognized_amount ?? 0), 0);
const byMacro = rows.reduce((acc, row) => {
  acc[row.macro_service_type] = (acc[row.macro_service_type] ?? 0) + 1;
  return acc;
}, {});

return [
  {
    json: {
      status: 'ok',
      appliedRevenueEventCount: rows.length,
      recognizedAmount: Math.round(recognizedAmount * 100) / 100,
      byMacro,
      sample: rows.slice(0, 10),
    },
  },
];
